mapper.select:
SELECT t1.id as sampleId, t2.check_item_id AS checkItemId, t2.check_item_name AS checkItemName, t1.times AS times, t1.unit_price AS checkPrice, t1.standard_id AS standardId, CONCAT(t3.CODE,'《',t3.NAME,'》') As standardName, t1.method_id AS methodId, t4.name AS methodName FROM test_entrusted_sample_checkitem_rel AS t1 LEFT JOIN test_product_item AS t2 ON t1.check_item_id = t2.check_item_id LEFT JOIN test_standard_file AS t3 ON t1.standard_id = t3.id LEFT JOIN test_method As t4 ON t4.id = t1.method_id
and t1.sample_id = #{sampleId}
and t1.entrust_id = #{entrustmentId}

SELECT t1.check_item_id AS checkItemId, t2.check_item_name AS checkItemName, t1.method_id AS methodId FROM test_entrusted_sample_checkitem_rel AS t1 LEFT JOIN test_product_item AS t2 ON t1.check_item_id = t2.check_item_id
and t1.sample_id = #{sampleId}
and t1.entrust_id = #{entrustmentId}

SELECT t1.id id, t1.company_id companyId, t2.company_name companyName, t1.product_id productId, t1.sample_name sampleName, t1.sample_code sampleCode, t1.specs specs, t1.batch_number batchNumber, t1.manufacturer manufacturer, t1.sample_origin sampleOrigin, t1.outward outward, t1.picture picture, t1.save_place savePlace, t1.admin admin, t1.sample_groups sampleGroups, t1.quantity_per_group quantityPerGroup, t1.inspector inspector, t1.received_date receivedDate, t1.sample_requirement sampleRequirement, t1.generation generation, t1.state state, t1.check_date checkDate, t1.remark remark, t1.insert_flag insertFlag FROM test_sample t1 LEFT JOIN test_company t2 ON t1.company_id = t2.company_id
and product_id = #{productId}
and manufacturer LIKE CONCAT('%',#{manufacturer},'%')
and batch_number LIKE CONCAT('%',#{batchNumber},'%')
and received_date=#{receivedDate}
and state=#{state}
and company_id=#{companyId}
and insert_flag=#{insertFlag}

mapper.delete:
DELETE
FROM test_entrusted_sample_details_rel
WHERE entrustment_id = #{entrustmentId}
  and sample_id = #{sampleId}

mapper.select:
SELECT DISTINCT t1.standard_id
FROM test_entrusted_sample_standard_rel as t1
         LEFT JOIN test_standard_file as t2 ON t1.standard_id = t2.id
WHERE t1.sample_id = #{sampleId}
  and t1.entrustment_id = #{entrustmentId}

SELECT DISTINCT t1.standard_id as standardId,
                                CONCAT(t2.name,'《',t2.code,'》') as standardName
        FROM test_entrusted_sample_standard_rel as t1
                 LEFT JOIN test_standard_file as t2 ON t1.standard_id = t2.id
        WHERE t1.sample_id = #{sampleId}
          and t1.entrustment_id = #{entrustmentId}

SELECT t1.company_id, t1.company_name, t1.sample_name, t1.specs, t1.manufacturer, t1.sample_origin, t1.outward, t1.sample_groups, t1.quantity_per_group, t1.inspector, t1.received_date, t1.sample_requirement, t1.generation, t1.product_id, t1.insert_flag, t2.id, t2.sample_code, t2.batch_number, t2.picture FROM ( SELECT DISTINCT t1.company_id, t2.company_name, sample_name, specs, manufacturer, sample_origin, outward, sample_groups, quantity_per_group, inspector, received_date, sample_requirement, generation, product_id, insert_flag FROM test_sample t1 LEFT JOIN test_company t2 ON t1.company_id = t2.company_id ) t1 LEFT JOIN ( SELECT id, sample_code, batch_number, picture, insert_flag FROM test_sample ) t2 ON t1.insert_flag = t2.insert_flag
and product_id = #{productId}
and manufacturer LIKE CONCAT('%',#{manufacturer},'%')
and sample_origin LIKE CONCAT('%',#{sampleOrigin},'%')
and batch_number LIKE CONCAT('%',#{batchNumber},'%')
and state=#{state}
and company_id=#{companyId}
and str_to_date( t1.received_date, '%Y-%m-%d' ) >= str_to_date( #{beginDate}, '%Y-%m-%d' )
and str_to_date( t1.received_date, '%Y-%m-%d' ) <= str_to_date( #{endDate}, '%Y-%m-%d' )
ORDER BY t1.insert_flag desc

SELECT t1.company_id, t1.company_name, t1.sample_name, t1.specs, t1.manufacturer, t1.sample_origin, t1.outward, t1.sample_groups, t1.quantity_per_group, t1.inspector, t1.received_date, t1.sample_requirement, t1.generation, t1.product_id, t1.insert_flag FROM ( SELECT DISTINCT t1.company_id, t2.company_name, sample_name, specs, manufacturer, sample_origin, outward, sample_groups, quantity_per_group, inspector, received_date, sample_requirement, generation, product_id, insert_flag FROM test_sample t1 LEFT JOIN test_company t2 ON t1.company_id = t2.company_id ) t1
and product_id = #{productId}
and manufacturer LIKE CONCAT('%',#{manufacturer},'%')
and sample_origin LIKE CONCAT('%',#{sampleOrigin},'%')
and batch_number LIKE CONCAT('%',#{batchNumber},'%')
and state=#{state}
and company_id=#{companyId}
and str_to_date( t1.received_date, '%Y-%m-%d' ) >= str_to_date( #{beginDate}, '%Y-%m-%d' )
and str_to_date( t1.received_date, '%Y-%m-%d' ) <= str_to_date( #{endDate}, '%Y-%m-%d' )
ORDER BY t1.insert_flag desc

SELECT id, sample_code, batch_number, picture, insert_flag FROM test_sample
WHERE insert_flag IN

    #{flag}
